          }
        }

        & when not(@flavor = latte) {
          background-color: @red;
          color: @surface1;

          &:hover {
            background-color: lighten(@red, 5%);
          }
        }
      }

      /* Success */
      &.c37751f6 {
        & when (@flavor = latte) {
          background-color: lighten(@green, 30%);

          &:hover {
            background-color: lighten(@green, 25%);
          }
        }

        & when not(@flavor = latte) {
          background-color: @green;
          color: @surface1;

          &:hover {
