    }
    #pkg-list-exact-match {
      color: @base;
      background-color: @accent;
    }

    /* Username links */
    a[aria-label^="publisher"]:hover {
      color: @accent;
    }

    /* --- FOOTER --- */

    footer {
      h3 {
        color: @text;
      }
      ul a:hover {
        color: @accent;
      }
      a[href="https://github.com/npm"] svg {
        > polygon {
          fill: @base;
        }

        > rect {
          fill: @text;
        }
      }
      a[href="https://github.com"] svg {
        fill: @text;
      }
      &::after {
        background-image: @npmGradient;
      }
    }

    --color-prettylights-syntax-comment: @overlay2;
