@var select lightFlavor "Light Flavor" ["latte:Latte*", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha"]
@var select darkFlavor "Dark Flavor" ["latte:Latte", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha*"]
@var select accentColor "Accent" ["rosewater:Rosewater", "flamingo:Flamingo", "pink:Pink", "mauve:Mauve*", "red:Red", "maroon:Maroon", "peach:Peach", "yellow:Yellow", "green:Green", "teal:Teal", "blue:Blue", "sapphire:Sapphire", "sky:Sky", "lavender:Lavender", "subtext0:Gray"]
==/UserStyle== */

@import "https://userstyles.catppuccin.com/lib/lib.less";

@-moz-document domain("adventofcode.com") {
  :root {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();

    body {
      background: @base;
      color: @text;

      header h1 a,
      header h1 span {
        color: @green;
        text-shadow: 0 0 2px @green, 0 0 5px @green;
      }

      a {
        color: @green;
      }

      .star-count {
        color: @yellow;
      }

      .quiet {
        color: @subtext0;
        opacity: 1;
      }

      .share,
      .share:hover,
      input[type="submit"] {
        color: @green;
      }

      main {
        article {
          em {
            color: @text;
            text-shadow: 0 0 5px @text;
          }

          h2 {
            color: @text;
          }

          input[type="radio"]:checked ~ span,
          input[type="checkbox"]:checked ~ span {
            color: @text;
          }

          input[type="radio"] ~ span:hover,
          input[type="radio"] ~ span:focus,
          input[type="checkbox"]:hover ~ span,
          input[type="checkbox"]:focus ~ span {
            background-color: @crust;
          }
        }
        .supporter-badge {
          color: @yellow;
        }

        .supporter-badge:hover {
          color: @yellow;
          text-shadow: 0 0 5px @yellow;
        }

        .sponsor-badge {
          color: @blue;
        }

        .sponsor-badge:hover,
        .sponsor-badge:focus {
          color: @blue;
          text-shadow: 0 0 5px @blue;
        }

        .leaderboard-entry {
          .leaderboard-position {
            color: @subtext1;
          }
          .leaderboard-totalscore {
            color: @text;
          }
        }

        .leaderboard-daylinks-selected {
          color: @text;
          text-shadow: 0 0 5px @text;
        }

        .leaderboard-daylinks-selected:hover {
          color: @green;
        }

        .leaderboard-anon {
          opacity: 1;
          color: @subtext0;
        }
        .calendar {
          .calendar-color-w {
            color: @text;
          }
          .calendar-color-s {
            color: @yellow;
          }
          .calendar-color-c {
            color: @subtext1;
          }
          .calendar-color-g3 {
            color: darken(@green, 3%);
          }
          .calendar-color-g2 {
            color: @green;
          }
          .calendar-color-g4 {
            color: darken(@green, 3.5%);
          }
          .calendar-color-u {
            color: @sky;
          }
          .calendar-color-a {
            color: @subtext0;
          }
          .calendar-color-g1 {
            color: darken(@green, 2.5%);
          }
          .calendar-color-g0 {
            color: darken(@green, 2%);
          }
          .calendar-color-l {
            color: @red;
          }
          .calendar-mark-complete {
            color: @yellow;
          }
          .calendar-mark-verycomplete {
            color: @yellow;
          }
          .calendar-day {
            color: @subtext1;
          }
          #calendar-countdown {
            color: @subtext1;
          }

          span {
            color: @surface0;
          }

          a {
            color: @surface2;
          }
        }

        .day-success {
          color: @yellow;
          text-shadow: 0 0 5px @yellow;
        }

        .stats-both {
          color: @yellow;
        }

        .stats-firstonly {
          color: @overlay0;
        }

        a:hover {
          background-color: @mantle !important;
        }

        input[type="text"],
        textarea,
        code::before {
          border-color: @surface0;
          background: @crust;
        }
      }
    }
  }
}

/* ==UserStyle==
@name paste.rs Catppuccin
@namespace github.com/catppuccin/userstyles/styles/paste.rs
@homepageURL https://github.com/catppuccin/userstyles/tree/main/styles/paste.rs
@version 2025.09.06
@updateURL https://github.com/catppuccin/userstyles/raw/main/styles/paste.rs/catppuccin.user.less
@supportURL https://github.com/catppuccin/userstyles/issues?q=is%3Aopen+is%3Aissue+label%3Apaste.rs
@description Soothing pastel theme for paste.rs
@author Catppuccin
@license MIT

@preprocessor less
@var select lightFlavor "Light Flavor" ["latte:Latte*", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha"]
@var select darkFlavor "Dark Flavor" ["latte:Latte", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha*"]
@var select accentColor "Accent" ["rosewater:Rosewater", "flamingo:Flamingo", "pink:Pink", "mauve:Mauve*", "red:Red", "maroon:Maroon", "peach:Peach", "yellow:Yellow", "green:Green", "teal:Teal", "blue:Blue", "sapphire:Sapphire", "sky:Sky", "lavender:Lavender", "subtext0:Gray"]
==/UserStyle== */

@import "https://userstyles.catppuccin.com/lib/lib.less";

@-moz-document domain("paste.rs") {
  :root {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();

    body {
      background-color: @base;
      color: @text;
    }

    a {
      color: @accent;
    }

    /* Web UI */
    textarea,
    select,
    input[type="submit"] {
      background-color: @base;
      color: @text;
      border-color: @overlay0;
      border-radius: 4px;
    }
    textarea:focus,
    select:focus,
    input[type="submit"]:focus {
      border-color: @accent;
      outline-color: @overlay0;
    }
    input[type="submit"]:hover {
      background-color: @mantle;
    }

    main {
      color: @text;
      border-color: @surface0;
    }

    .code.gutter {
      background-color: @base !important;
      span {
        /* Line Numbers */
        color: @overlay0 !important;
      }
    }

    article.markdown-body {
      color: @text;

      h6 {
        color: @text;
      }

      a {
        color: @accent;
      }

      img {
        background: none;
      }

      pre {
        background: @surface0;
      }

      h1,
      h2,
      h3,
      h4,
      h5,
      h6 {
        border-color: @surface0;
      }

      blockquote {
        border-color: @surface1;

        p {
          color: @text;
        }
      }

      table {
        border-color: @surface0 !important;
        tr,
        th,
        td {
          border-color: @surface1;
          background: none !important;
        }
      }
    }

    /* Syntax-highlighted code */
    .code.text > pre {
      background-color: @base !important;
      background-image: none;

      span {
        color: red !important;
      }

      /* General Text, Braces, Delimiters, Parameters, Classes, Metadata */
      span[style*="color:#323232"] {
        color: @text !important;
      }

      /* Keywords, Operators */
      span[style*="color:#a71d5d"] {
        color: @mauve !important;
      }

      /* Strings */
      span[style*="color:#183691"],
      span[style*="color:#ed6a43"] {
        color: @green !important;
      }

      /* Comments */
      span[style*="color:#969896"] {
        color: @overlay2 !important;
      }

      /* Constants, Numbers */
      span[style*="color:#0086b3"] {
        color: @peach !important;
      }

      /* Methods, Functions */
      span[style*="color:#795da3"],
      span[style*="color:#62a35c"],
      span[style*="color:#63a35c"] {
        color: @blue !important;
      }

      /* Errors */
      span[style*="background-color:#f5f5f5"][style*="color:#b52a1d"] {
        color: @text !important;
        background: fade(@red, 60%) !important;
      }
    }
  }
}

