@var select darkFlavor "Dark Flavor" ["latte:Latte", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha*"]
@var select accentColor "Accent" ["rosewater:Rosewater", "flamingo:Flamingo", "pink:Pink", "mauve:Mauve*", "red:Red", "maroon:Maroon", "peach:Peach", "yellow:Yellow", "green:Green", "teal:Teal", "blue:Blue", "sapphire:Sapphire", "sky:Sky", "lavender:Lavender", "subtext0:Gray"]
==/UserStyle== */

@import "https://userstyles.catppuccin.com/lib/lib.less";

@-moz-document domain("chatgpt.com") {
  @import url("https://unpkg.com/@catppuccin/highlightjs@1.0.0/css/catppuccin-variables.important.css");

  .light {
    #catppuccin(@lightFlavor);
  }

  .dark {
    #catppuccin(@darkFlavor);
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();
    #lib.css-variables();

    &, .popover {
      --text-primary: @text;
      --text-secondary: @subtext1;
      --text-tertiary: @subtext0;
      --text-quaternary: @overlay2;
      --bg-primary: @base;
      --bg-secondary: @surface0;
      --bg-tertiary: @surface1;

      --bg-elevated-secondary: @mantle; // sidebar

      --main-surface-primary: @base;
      --main-surface-secondary: @surface0;
      --main-surface-tertiary: @surface1;
      --interactive-bg-secondary-hover: @surface1;
      --interactive-bg-secondary-press: @surface0;

      --interactive-label-accent-default: @accent; // some dropdowns in settings

      --border-light: @surface0;
      --border-default: @surface1;
      --border-medium: @surface2;
      --interactive-border-focus: @overlay0;

      --theme-user-msg-bg: @surface0;
      --theme-submit-btn-bg: @accent;
      --theme-submit-btn-text: @base;

      --theme-secondary-btn-bg: @surface1;
      --theme-secondary-btn-text: @text;

      --sidebar-surface: @mantle; // modal backgrounds
      --sidebar-surface-primary: @mantle; // syntax highlighted code block backgrounds

      --surface-hover: @surface0; // some button hovers

      --icon-tertiary: @overlay2;

      --text-status-error: @red;

      // chat input prompt border
      --shadow-color-1: fade(@mantle, 50%);
      --shadow-color-2: fade(@text, 80%);

      .__menu-item[data-color="danger"] {
        --menu-item-highlighted: fade(@red, 20%);
        --menu-item-active: fade(@red, 30%);
        --menu-item-open: fade(@red, 30%);
      }

      /* Markdown */

      code:not([class]) {
        background-color: @surface0;
      }

      code[class*="language-"],
      pre[class*="language-"],
      code.hljs {
        color: @text !important;
      }

      /* Components */

      .btn-primary {
        background-color: @text;
        color: @base;
      }

      .btn-purple {
        color: @base;
        background-color: @accent;

        &:hover {
          background-color: lighten(@accent, 5%);
        }

        &:focus, &:active {
          background-color: darken(@accent, 5%);
        }
      }

      .btn-danger-outline {
        color: @red;
        border-color: @red;
      }

      .btn-ghost {
        &:not(:disabled) {
          &:hover {
            background-color: @surface0;
          }
        }
      }

      /* Dark Overrides */
      .bg-token-bg-primary {
        background-color: var(--bg-primary);
      }
      .bg-token-main-surface-primary {
        background-color: var(--main-surface-primary);
      }
      .bg-token-sidebar-surface {
        background-color: var(--sidebar-surface);
      }

      /* Tailwind Utilities */
      .__tailwind-utility(@color, @shade, @value) {
        .text-@{color}-@{shade},
        .dark\:text-@{color}-@{shade} {
          color: @value;
        }
        .bg-@{color}-@{shade},
        .dark\:bg-@{color}-@{shade} {
          background-color: @value;
        }
        .border-@{color}-@{shade} {
          border-color: @value;
        }
        .radix-state-checked\:bg-@{color}-@{shade}[data-state="checked"] {
          background-color: @value;
        }
      }

      .__tailwind-utility(green, 600, @green); // confirmation toasts
      .__tailwind-utility(red, 500, @red); // failure toasts
      .__tailwind-utility(blue, 400, @accent); // toggled checkmarks
      .__tailwind-utility(gray, 600, @overlay0); // untoggled checkmarks
      .__tailwind-utility(gray, 500, @overlay2); // faint text in/and dividers

      .text-white {
        color: @base;
      }

      .bg-black {
        background-color: @mantle;
      }
    }
  }
}

@-moz-document domain("auth.openai.com") {
  :root {
    @media (prefers-color-scheme: light) {
      #catppuccin(@lightFlavor);
    }
    @media (prefers-color-scheme: dark) {
      #catppuccin(@darkFlavor);
    }
  }

  #catppuccin(@flavor) {
    #lib.palette();
    #lib.defaults();

    color: @text;

    background-color: @base;
    --main-page-background: @base;

    // Logo
    a[href="https://chatgpt.com"] > svg {
      filter: @text-filter;
    }

    --text-primary: @text;
    --text-secondary: @subtext1;
    --text-tertiary: @subtext0;

    --accent-blue: @accent;
    --link: @accent;

    --border-medium: @surface2;

    --button-primary-background: @text;
    --button-primary-hover: @subtext1;
    --button-text-on-primary: @base;

    --button-outline-hover: @surface0;

    --gray-100: @surface2; // divider lines

    input {
      color: @text;
    }

    [class*="_toggleVisibilityButton"]:where(:hover, :focus-visible)::before {
      background-color: @surface0;
    }

    [data-overlay-container] [class*="_tooltip"] {
      --tooltip-background-color: @mantle !important;
      --tooltip-color: @text !important;
    }
  }
}

